Steps:
[GQL-OP get_config]
  query {
    productConfiguration(
      configurableProductId: "{{ring_id}}"
      storeId: "{{STORE_ID}}"
    ) {
      configurationSections {
        id
        name
        type
        isRequired
        options {
          id
          text
          quantity
        }
      }
    }
  }
[GQL-EXEC get_config]
